        int code;
        std::cin >> code;
        if (code == 1) {
            std::cout << "unique_ptr\n";
        } else if (code == 2) {
            std::cout << "shared_ptr\n";
        } else {
            std::cout << "weak_ptr\n";
        }
    }
    return 0;
}

