solution_code:
#include <iostream>
#include <memory>

std::shared_ptr<int> process(std::unique_ptr<int> p) {
    return std::make_shared<int>(*p * 2);
}

int main() {
    int v;
    std::cin >> v;
    auto u = std::make_unique<int>(v);
    std::cout << "Unique: " << *u << "\n";
    auto s = process(std::move(u));
    std::cout << "Shared: " << *s << "\n";
    return 0;
}
